const SetValue = async (context) => {  
  // Get inspection details
  const inspectionType = context?.Form?.InspectionPage?.InspectionType?.Value || "";
  const category = context?.Form?.InspectionPage?.Category?.Value || "";
  const postInspection = context?.Form?.InspectionPage?.InspectionStatus?.Value || "";
  const reInspection = context?.Form?.InspectionPage?.ReInspectionStatus?.Value || "";
  const contactAttempt = context?.Form?.InspectionPage?.ContactAttempt?.Value || "";

  // QC Flag Check
  const gridRowCount = Number(context?.Form?.InspectionPage?.TotalMeasureCount?.Value) || 0;  
  const flag = !!context?.Form?.InspectionPage?.QCSampleBatchFlag_c?.Value;

  if (category.includes("QC") && gridRowCount <= 0) {
    // No measures yet - check flag
      return flag ? "Marked for Inspection" : "Deferred";
  }

  // Normal flow - only reached if:
  // 1. Not QC category, OR
  // 2. QC category with flag=true AND measures exist

  // Get the current status based on inspection type
  const currentStatus = inspectionType == "Re-Inspection" ? reInspection : postInspection;

  // Check if status is "Open" and contact attempt exists
  if (currentStatus == "Open" && contactAttempt !== "") {
    return `In Progress ${contactAttempt}`.trim();
  }

  // Return appropriate status without inspection type
  return currentStatus.trim() || "Deferred";
